return items.map(name => ({
  json: {
    idChecklist,
    name
  }
}));

// =========================
// 1) بيانات AI Agent
// =========================
const aiData = $('AI Agent Process Case & Prepare HR Output').first().json;

// =========================
// 2) بيانات Extractor (الأهم)
// =========================
const extractedData = $('Information Extractor1').first().json;

// =========================
// 3) حساب كود العجز الجديد
// =========================
const rows = $('Get row(s) in sheet').all();

let maxCode = 0;

for (const row of rows) {
  const value = parseInt(row.json["كود العجز"]);
  if (!isNaN(value) && value > maxCode) {
    maxCode = value;
  }
}

const nextCode = maxCode + 1;

// =========================
// 4) استخراج نوع العجز
// =========================
let shortageType = aiData.shortage_type;

if (!shortageType) {
  const text = (aiData.reason || "").toString();

  if (
    text.includes("فقد") ||
    text.includes("مفقود") ||
    text.includes("ضياع")
  ) {
    shortageType = "فقد";
  } 
  else if (
    text.includes("عدم توريد") ||
    text.includes("لم يتم توريد") ||
    text.includes("توريد ناقص")
  ) {
    shortageType = "عدم توريد";
  } 
  else if (
    text.includes("سرقة") ||
    text.includes("اختلاس") ||
    text.includes("استيلاء")
  ) {
    shortageType = "سرقة";
  } 
  else {
    shortageType = "غير محدد";
  }
}

// =========================
// 5) استخراج job_code صح
// =========================
const jobCode =
  extractedData.job_code ||   // المصدر الأساسي
  aiData.job_code ||          // fallback
  extractedData.msg_id ||     // fallback احتياطي
  aiData.msg_id ||            // fallback أخير
  null;

// =========================
// 6) رجوع كل البيانات
// =========================
return [
  {
    json: {
      ...aiData,

      // أهم تعديل
      job_code: jobCode,

      // اختياري لو عايز تحتفظ بالمرجع
      reference_id: extractedData.msg_id || aiData.msg_id,

      next_shortage_code: nextCode,
      shortage_type: shortageType
    }
  }
];

